mapper.select:
SELECT COUNT(*)
FROM post_view_history
WHERE user_id = #{userId}
  AND post_id = #{postId}

SELECT COUNT(*)
FROM ai_logs
WHERE user_id = #{userId}
  AND post_id = #{postId}
  AND ai_type IN ('SUMMARY', 'REVIEW_CARD', 'QUESTION')
  AND success = 1

SELECT COUNT(DISTINCT collection_id)
FROM favorite_collection_items
WHERE user_id = #{userId}
  AND post_id = #{postId}

mapper.update:
UPDATE favorite_collection_items
SET importance_score = #{importanceScore},
    score_factors = #{scoreFactors}
WHERE collection_id = #{collectionId}
  AND post_id = #{postId}
  AND user_id = #{userId}

UPDATE favorite_collection_items
SET pinned = #{pinned}
WHERE collection_id = #{collectionId}
  AND post_id = #{postId}
  AND user_id = #{userId}
